@ARTICLE{10.3390/nu18050826,
	author = {İmre KE and Akyol A},
	title = {Propolis in Obesity and Related Metabolic Disorders: Mechanistic and Clinical Insights-A Scoping Review.},
	journal = {Nutrients},
	year = {2026},
	abstract = {OBJECTIVES: Obesity and related metabolic disorders, including insulin resistance, dyslipidemia, and non-alcoholic fatty liver disease, represent major global health challenges. Growing interest in complementary strategies has brought propolis, a resinous bee-derived product rich in phenolic and flavonoid compounds, into focus. This scoping review aimed to map and synthesize available in vitro, in vivo, and clinical evidence regarding the metabolic effects of whole propolis preparations and propolis-derived bioactive compounds in obesity-related contexts. METHODS: The review was conducted in accordance with the PRISMA-ScR framework and included experimental and human studies evaluating adipogenesis, lipid and glucose metabolism, oxidative stress, inflammatory signaling, non-alcoholic fatty liver disease-related outcomes, and gut microbiota modulation. RESULTS: Across preclinical models, propolis preparations have been associated with modulation of antioxidant defenses, attenuation of inflammatory signaling, regulation of adipogenic transcriptional programs, and alterations in gut microbiota composition and barrier integrity. Clinical evidence suggests modest improvements in selected metabolic and inflammatory biomarkers; however, effects on body weight and adiposity remain inconsistent. Interpretation is limited by heterogeneity in propolis type, extraction method, chemical standardization, dosing strategies, and study design. CONCLUSIONS: Overall, current evidence indicates that propolis may influence obesity-related metabolic pathways, primarily at the level of biomarker modulation. Nevertheless, mechanistic causality and long-term clinical efficacy require confirmation through well-designed, adequately powered, and chemically standardized trials.},
	doi = {10.3390/nu18050826},
	pmid = {41829996 [Indexed for MEDLINE]},
	note = {PMC12987181}
}

@ARTICLE{10.3390/nu18050786,
	author = {Tago A and Kagawa N and Sakai T and Tian A and Takano S, Nahrowi and Nomura J and Suzuki T},
	title = {Compounds Contributing to the Modulation of Visceral Adiposity and Hepatic Lipid Metabolism in High-Fat-Diet-Fed Rats by Pometia pinnata (Matoa) Peel Powder: Identification of Pancreatic Lipase Inhibitors.},
	journal = {Nutrients},
	year = {2026},
	abstract = {Background:Pometia pinnata (matoa) peel powder attenuates high-fat diet-induced adiposity and hepatic lipid accumulation in rats, but the responsible compounds remain unclear. This study aimed to identify the bioactive compounds that may contribute to this phenotype, with an emphasis on pancreatic lipase inhibition as a candidate mechanism. Methods: Rats received high-fat diets containing matoa peel powder, or its water- or ethanol extraction residue. Visceral fat accumulation, hepatic lipid deposition, and serum lipid profiles were evaluated. An ethanol extract was fractionated by activity-guided column chromatography based on pancreatic lipase-inhibitory activity, and structures were identified by nuclear magnetic resonance analysis. Static in vitro gastrointestinal digestion was performed to assess inhibition of fatty acid release by the extract or isolated compounds. Results: The visceral adiposity- and hepatic lipid-modulating effects observed with matoa peel powder were retained in the water extraction residue but not in the ethanol extraction residue, suggesting removal of bioactive constituents by ethanol extraction. The ethanol extract inhibited pancreatic lipase (IC50 = 740 μg/mL). Two active compounds-hederagenin saponin and protocatechuic acid-were isolated, and both inhibited pancreatic lipase (IC50 = 149 μmol/L and 404 μmol/L, respectively). Under simulated digestion in vitro, the ethanol extract and protocatechuic acid reduced free fatty acid release, whereas hederagenin saponin did not. Conclusions: Matoa peel powder contains ethanol-soluble constituents, including pancreatic lipase-inhibitory compounds that may contribute to the modulation of adiposity and hepatic lipid metabolism in high-fat-diet-fed rats. The attenuation of individual-compound activity under simulated digestion is consistent with matrix- and intestinal milieu-dependent effects, and supports a multi-component mechanism involving saponins, phenolics (protocatechuic acid), and their intestinal biotransformation products.},
	doi = {10.3390/nu18050786},
	pmid = {41829956 [Indexed for MEDLINE]},
	note = {PMC12987302}
}

@ARTICLE{10.3390/molecules31050887,
	author = {Schifano E and Zinno P and Natella F and Pompa L and Sonaglia E and Spaziani S and Sharbaf M and Esposito F and Cirillo T and Squillante J and Maglione G and Mancini P and Angeloni A and Santarelli ML and Devirgiliis C and Uccelletti D},
	title = {Coffee Silverskin Supplementation Alleviates High-Glucose-Diet-Induced Obesity by Modulating Lipogenic Gene Expression in Caenorhabditis elegans Model.},
	journal = {Molecules},
	year = {2026},
	abstract = {Coffee silverskin (CSS), the major by-product of coffee roasting, is reported to contain bioactive compounds, including xanthines and polyphenols, showing promising potential for food and nutraceutical applications. This study investigated the beneficial effects of CSS hydroalcoholic extracts, which were chemically characterized by Attenuated Total Reflectance-Fourier-Transform Infrared Spectroscopy and ElectroSpray Ionization tandem Mass Spectrometry, on Caenorhabditis elegans physiology. CSS supplementation improved healthspan-related parameters and delayed aging-associated functional decline, without significantly extending lifespan in wild-type nematodes. Treated worms exhibited a 57% reduction in reactive oxygen species (ROS) levels and upregulation of antioxidant genes (gst-4 and sod-3), suggesting that CSS mitigates oxidative stress through the DAF-2/DAF-16 pathway. Under high-glucose diet conditions, CSS reduced lipid droplet accumulation and modulated the expression of metabolic genes, including upregulation of nhr-49 which is a key regulator of fatty acid oxidation. CSS restored lipid homeostasis and rescued the shortened lifespan of obese nhr-49 mutant worms, suggesting enhanced β-oxidation. Moreover, CSS modulated serotonergic signaling by increasing tph-1 and ser-6 expression, linking its effects to serotonin-mediated regulation of fat metabolism. Finally, CSS promoted the growth of probiotic strains, suggesting potential prebiotic properties. Overall, these findings identify CSS as a metabolic modulator capable of alleviating oxidative and metabolic stress, supporting its sustainable application in the development of functional foods and nutraceuticals.},
	doi = {10.3390/molecules31050887},
	pmid = {41828874 [Indexed for MEDLINE]},
	note = {PMC12986101}
}

@ARTICLE{10.3390/molecules31050849,
	author = {Wilczak J and Prostek A, Karpiński P and Ciesielska K, Dzięgelewska-Sokołowska Ż and Gajewska M},
	title = {Fish Oil Alters the Metabolome, Antioxidative Potential, and Secretory Profile of Visceral Adipose Tissue in Mice with High-Fat Diet-Induced Obesity Compared with Other Dietary Fat Sources.},
	journal = {Molecules},
	year = {2026},
	abstract = {Dietary fat quality, determined by fatty acid composition, plays a central role in regulating adipose tissue function and metabolic homeostasis in obesity. This study examined whether different dietary fat sources modulate the secretory activity, antioxidant capacity, and metabolomic profiles of visceral adipose tissue (VAT) in mice with established high-fat diet (HFD)-induced obesity. Male C57BL/6J mice were rendered obese by long-term feeding with a lard-based HFD and subsequently maintained on isocaloric HFDs containing lard, coconut oil, olive oil, or fish oil. Antioxidant capacity, redox enzyme activities, adipokine levels, and untargeted metabolomic profiles of VAT were analyzed. Fish oil-enriched HFD significantly improved antioxidant potential and partially restored redox enzyme activity compared with the lard-based diet. It preserved adiponectin levels and reduced leptin accumulation in VAT. Multivariate metabolomic analyses showed clear separation of dietary groups and distinct metabolic signatures related to fat quality. Replacement of lard with fish oil induced a coordinated remodeling of the lipid and amino acid metabolism and reduced metabolites linked to mitochondrial overload and oxidative stress, whereas saturated fat-rich diets promoted patterns consistent with metabolic dysfunction. These findings indicate that dietary fat quality reshapes adipose tissue metabolism in obesity and highlights fish oil as a strategy to attenuate adipose tissue dysfunction.},
	doi = {10.3390/molecules31050849},
	pmid = {41828836 [Indexed for MEDLINE]},
	note = {PMC12986175}
}

@ARTICLE{10.3390/ijms27052287,
	author = {Lee S and Seo D and Yoo C and Kim HD and Suh HJ and Lee HJ},
	title = {Anti-Obesity Activity of Giant Centella asiatica Lava Seawater Extract (GCA-LS-90) Through Regulation of Adipocyte Differentiation and Lipid Metabolism In Vitro.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Obesity is well-known as a major risk factor for metabolic disorders, and natural compounds are being explored as alternatives to conventional therapies. While Centella asiatica is well known for its medicinal and dietary benefits, the biological activities of Giant Centella asiatica (GCA), especially when extracted with mineral-rich lava seawater, remain poorly characterized. This study aimed to evaluate the anti-adipogenic and lipid-metabolism-regulating effects of a novel GCA extract (GCA-LS-90) and its ability to stimulate GLP-1 secretion in vitro. GCA-LS-90 significantly inhibited lipid accumulation in 3T3-L1 adipocytes by up to 24.3% at 200 μg/mL (p < 0.001). It downregulated adipogenic transcription factors (C/EBPβ, C/EBPα, PPARγ) and lipogenic regulators (SREBP1c, FAS, G6PD, ME), while upregulating KLF2 (all p < 0.001). Western blotting confirmed reduced SREBP1c and SREBP2 protein expression, increased phosphorylation of AMPKα/ACC, and enhanced HSL activity (p < 0.05-0.001). In STC-1 cells, GCA-LS-90 increased GLP-1 secretion (53.5 pmol/L at 90 μg/mL vs. 41.3 pmol/L in control, p < 0.001). The major compounds, 3,5- and 4,5-di-O-caffeoylquinic acids, reproduced these effects. In conclusion, GCA-LS-90 modulated adipogenesis-, lipid-metabolism-, and GLP-1 secretion-related pathways in vitro, suggesting its potential as a functional ingredient for obesity management. Further in vivo studies are needed to confirm efficacy and translational relevance.},
	doi = {10.3390/ijms27052287},
	pmid = {41828505 [Indexed for MEDLINE]},
	note = {PMC12984701}
}

@ARTICLE{10.1371/journal.pone.0344452,
	author = {Li X and Min R},
	title = {Identification of core genes mediating the association between obesity and hepatocellular carcinoma: A bioinformatics study based on mitochondrial metabolism and immune pathways.},
	journal = {PLoS One},
	year = {2026},
	abstract = {PURPOSE: Obesity is strongly associated with hepatocellular carcinoma (HCC), yet the molecular mechanisms linking them remain unclear. This study aimed to identify mitochondrial metabolism-related genes bridging obesity and HCC and to investigate their role in regulating the metabolic-immune microenvironment. METHODS: Public transcriptomic datasets from obesity (derived from peripheral blood mononuclear cells) and HCC (derived from liver tissue) cohorts were integrated. A multi-step bioinformatic pipeline combining differential expression analysis (DEA), weighted gene co-expression network analysis (WGCNA), and machine learning (ML) algorithms was applied to identify and validate hub genes. Associations with the tumor immune microenvironment were assessed using ssGSEA and correlation analyses. RESULTS: 27 core genes were identified, significantly enriched in lipid metabolism and immune response pathways. Among these, ML highlighted ACAA1 and ADI1 as downregulated candidate genes. While discovery datasets showed high diagnostic potential, ADI1 exhibited more variable performance in obesity external validation compared to the robust consistency of ACAA1. Downregulation of both genes correlated with effector T/NK cell lipid-mediated functional exhaustion and disrupted networks of immune checkpoints and chemokines, reflecting an immunosuppressive microenvironment. CONCLUSIONS: ACAA1 and potentially ADI1 are downregulated candidate genes linking obesity to HCC. Their suppression likely drives obesity-related HCC progression by coupling mitochondrial metabolic reprogramming with immunosuppressive tumor microenvironment remodeling, representing potential therapeutic targets.},
	doi = {10.1371/journal.pone.0344452},
	pmid = {41801960 [Indexed for MEDLINE]},
	note = {PMC12970922}
}

@ARTICLE{10.2147/DDDT.S595588,
	author = {Chen S and Xue J and Shao Y and Liu H and Zhou F and Gu X and Zhou G and Xu T and Wang D and Tang L},
	title = {Gut-Derived Hippuric Acid Alleviates Hepatic Lipid Metabolism via UGDH/FOXK1/CD36 Axis in Obese Mice.},
	journal = {Drug Des Devel Ther},
	year = {2026},
	abstract = {BACKGROUND: Metabolic dysfunction-associated steatotic liver disease (MASLD) is the leading cause of chronic liver disease globally, creating an urgent need to elucidate its pathogenesis and develop effective therapeutic strategies. METHODS: In this study, we established obese mouse models using distinct dietary patterns. We then employed 16S rRNA sequencing and metabolomics to profile gut microbiota composition and identify differential metabolites in serum and intestinal contents. Using Limited proteolysis mass spectrometry, co-immunoprecipitation mass spectrometry and luciferase reporter assays were used to identify the downstream molecular mechanisms. RESULTS: Our findings revealed that the abundance of hippuric acid (HA) was significantly decreased in the serum and gut of obese C57BL/6 mice, and it positively correlated with the abundance of Akkermansia and Alistipes. Notably, HA supplementation effectively reduced body weight and alleviated hepatic lipid accumulation in obese mice. Mechanistically, we found that HA directly binds to UDP-glucose dehydrogenase (UGDH), enhancing its interaction with forkhead box protein K1 (FOXK1) in the cytoplasm, thereby preventing FOXK1 nuclear translocation. This event suppresses Cd36 transcription and mitigates hepatic lipid accumulation. Furthermore, silencing Ugdh attenuated the inhibitory effect of HA on FOXK1-mediated regulation of Cd36 transcription. CONCLUSION: We demonstrate a novel mechanism for regulating hepatic lipid metabolism through HA/UGDH/FOXK1/CD36 pathway. This study provides evidence supporting the potential of HA as a therapeutic metabolite for MASLD. Moreover, these results are derived from preclinical murine models, and further clinical studies are warranted to validate the efficacy of HA.},
	doi = {10.2147/DDDT.S595588},
	pmid = {41800297 [Indexed for MEDLINE]},
	note = {PMC12967088}
}

@ARTICLE{10.1016/j.foodres.2026.118574,
	author = {Cai J and Huang A and You L and Wang Z and Huang C and Huang R and Li Y and Liang T and Zhang F and Wu Q and Wang J and Zhu Z and Ding Y},
	title = {Neomycin-sensitive gut bacteria-derived brassicasterol mediates the anti-obesity effects of Cordyceps militaris polysaccharide.},
	journal = {Food Res Int},
	year = {2026},
	abstract = {Diet-based modulation of the gut microbiota has emerged as a promising strategy to alleviate obesity and its related complications. Our previous study demonstrated that polysaccharide derived from Cordyceps militaris (CMP) exerts anti-obesity effects, yet the specific mechanism linking gut microbiota to its metabolic impact remains unclear. Herein, we utilized murine models with distinct gut microbial profiles created via antibiotic cocktails to investigate these mechanisms. The protective effects of CMP against high-fat diet (HFD)-induced obesity and associated metabolic disturbances were substantially impaired in mice depleted of neomycin-sensitive gut bacteria. Metagenomic analyses further established that CMP required these bacteria to restore gut microbial homeostasis. Notably, we observed that CMP elevated hepatic levels of brassicasterol in a manner dependent on neomycin-sensitive gut bacteria. Brassicasterol treatment alone replicated the anti-obesity effects of CMP, as indicated by reduced body weight gain, improved lipid and glucose metabolism, and decreased inflammation. Through transcriptomic and functional analyses, we identified hepatic Apoa4 as a key downstream effector of brassicasterol. Our results indicated that brassicasterol upregulated Apoa4, facilitating lipid transport and suppressing inflammation both in vitro and in vivo. Collectively, our findings indicate that CMP exerts its anti-obesity effects through a neomycin-sensitive gut bacteria-brassicasterol-Apoa4 pathway. This work expands the mechanistic understanding of CMP and highlights a novel microbiota-metabolite-host regulatory axis for dietary intervention in metabolic disorders.},
	doi = {10.1016/j.foodres.2026.118574},
	pmid = {41794459 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.lfs.2026.124308,
	author = {Pan Z and Ding M and Gu W and Yu Z and Yi Q and Dai J and Wang L and Peng Y and Zhang Z and Zheng L},
	title = {Exercise improves high-fat diet-induced obesity and related cardiac dysfunction in Drosophila by regulating Dilp6 through FOXO in adipose tissue.},
	abstract = {Obesity is a common metabolic disease, and the development of obesity can lead to related cardiovascular diseases. Therefore, this article explores the relationship between exercise and Dilp6 in lipid metabolism and the resulting cardiac function damage, as well as the role of FOXO in the relationship between exercise and Dilp6. Our results show that adipose tissue-specific knockdown of Dilp6 leads to lipid accumulation, impaired cardiac function, and reduced exercise capacity in Drosophila. Exercise can regulate Dilp6 through FOXO, improving lipid accumulation and related cardiac function damage caused by Dilp6 downregulation. Therefore, our study provides a new theoretical basis for exercise to improve obesity and obesity-induced cardiac function damage.},
	doi = {10.1016/j.lfs.2026.124308},
	pmid = {41791487 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.molimm.2026.02.013,
	author = {Tong L and Su L and He J and Chen Y and Chen Z and Tang L and Wu X},
	title = {High fat diet promotes asthma by inhibiting the differentiation of regulatory T cells via E3 ubiquitin ligase ITCH.},
	journal = {Mol Immunol},
	year = {2026},
	abstract = {Obesity, a rising global health issue, has been linked to the exacerbation of asthma, increasing both the risk of onset and disease severity. High-fat diet (HFD) has been shown to influence immune responses and worsen asthma in murine models, although the exact mechanisms remain unclear. In our study, we found that HFD significantly reduced the population of regulatory T cells (Tregs) in the lungs and led to increased eosinophilic inflammation in asthma. HFD was linked to alterations in lipid metabolism, particularly through the activation of the lipogenic enzyme acetyl-CoA carboxylase (ACC1) and inhibition of fatty acid oxidation. Additionally, treatment with Etomoxir, a CPT-1a inhibitor, diminished Treg proportions and Foxp3 expression. We also revealed that the E3 ubiquitin ligase ITCH, which regulates Treg function, was downregulated at the protein level under HFD conditions, despite unchanged mRNA levels. Overall, our research findings highlight the impact of high-fat diets on Treg function and immune regulation, providing insights for potential therapeutic strategies targeting lipid metabolism in inflammatory diseases like asthma.},
	doi = {10.1016/j.molimm.2026.02.013},
	pmid = {41791173 [Indexed for MEDLINE]}
}
